func solve(c int64, connections [][]int64, queries [][]int64) []int64 {
    // Build the graph
    graph := make([][]int64, c+1)
    for _, conn := range connections {
        u, v := conn[0], conn[1]
        graph[u] = append(graph[u], v)
        graph[v] = append(graph[v], u)
    }

    // For each node, keep track of its parent in the DSU
    parent := make([]int64, c+1)
    // For each node, keep track of the minimum node in its connected component
    minNode := make([]int64, c+1)

    // Initialize DSU
    for i := 1; i <= c; i++ {
        parent[i] = i
        minNode[i] = int64(i)
    }

    // Find function with path compression
    func find(x int64) int64 {
        if parent[x] != x {
            parent[x] = find(parent[x])
        }
        return parent[x]
    }

    // Union function
    func union(x, y int64) bool {
        rootX := find(x)
        rootY := find(y)
        if rootX == rootY {
            return false
        }
        // Union by size (here we just use the min node for simplicity)
        if minNode[rootX] > minNode[rootY] {
            parent[rootX] = rootY
            minNode[rootY] = min(minNode[rootY], minNode[rootX])
        } else {
            parent[rootY] = rootX
            minNode[rootX] = min(minNode[rootX], minNode[rootY])
        }
        return true
    }

    // Build the DSU structure using BFS
    for i := 1; i <= c; i++ {
        if parent[i] == i {
            queue := []int64{i}
            visited := make([]bool, c+1)
            visited[i] = true
            for len(queue) > 0 {
                node := queue[0]
                queue = queue[1:]
                for _, neighbor := range graph[node] {
                    if !visited[neighbor] {
                        visited[neighbor] = true
                        parent[neighbor] = node
                        minNode[node] = min(minNode[node], minNode[neighbor])
                        queue = append(queue, neighbor)
                    }
                }
            }
        }
    }

    // Process queries
    result := []int64{}
    offline := make([]bool, c+1)

    for _, query := range queries {
        typeQuery := query[0]
        x := query[1]
        if typeQuery == 1 {
            if offline[x] {
                // Find the root of x
                root := find(x)
                // Find the minimum node in the component
                minInComponent := minNode[root]
                // Check if there are any online nodes in the component
                hasOnline := false
                for i := 1; i <= c; i++ {
                    if find(int64(i)) == root && !offline[i] {
                        hasOnline = true
                        break
                    }
                }
                if hasOnline {
                    result = append(result, minInComponent)
                } else {
                    result = append(result, -1)
                }
            } else {
                result = append(result, x)
            }
        } else {
            // Mark x as offline
            offline[x] = true
        }
    }

    return result
}

func min(a, b int64) int64 {
    if a < b {
        return a
    }
    return b
}
