    const graph: number[][] = Array.from({ length: c + 1 }, () => []);
    for (const [u, v] of connections) {
        graph[u].push(v);
        graph[v].push(u);
    }

    // For each node, keep track of its parent in the DSU
    const parent: number[] = Array(c + 1).fill(0);
    // For each node, keep track of the minimum node in its connected component
    const minNode: number[] = Array(c + 1).fill(0);

    // Initialize DSU
    for (let i = 1; i <= c; i++) {
        parent[i] = i;
        minNode[i] = i;
    }

    // Find function with path compression
    function find(x: number): number {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    // Union function
    function union(x: number, y: number): boolean {
        const rootX = find(x);
        const rootY = find(y);
        if (rootX === rootY) {
            return false;
        }
        // Union by size (here we just use the min node for simplicity)
        if (minNode[rootX] > minNode[rootY]) {
            parent[rootX] = rootY;
            minNode[rootY] = Math.min(minNode[rootY], minNode[rootX]);
        } else {
            parent[rootY] = rootX;
            minNode[rootX] = Math.min(minNode[rootX], minNode[rootY]);
        }
        return true;
    }

    // Build the DSU structure using BFS
    for (let i = 1; i <= c; i++) {
        if (parent[i] === i) {
            const queue: number[] = [i];
            const visited: boolean[] = Array(c + 1).fill(false);
            visited[i] = true;
            while (queue.length > 0) {
                const node = queue.shift()!;
                for (const neighbor of graph[node]) {
                    if (!visited[neighbor]) {
                        visited[neighbor] = true;
                        parent[neighbor] = node;
                        minNode[node] = Math.min(minNode[node], minNode[neighbor]);
                        queue.push(neighbor);
                    }
                }
            }
        }
    }

    // Process queries
    const result: number[] = [];
    const offline: boolean[] = Array(c + 1).fill(false);

    for (const [type, x] of queries) {
        if (type === 1) {
            if (offline[x]) {
                // Find the root of x
                const root = find(x);
                // Find the minimum node in the component
                const minInComponent = minNode[root];
                // Check if there are any online nodes in the component
                let hasOnline = false;
                for (let i = 1; i <= c; i++) {
